import Image from "next/image";

interface SectionDividerProps {
  variant?: "ornate" | "simple";
  className?: string;
}

export default function SectionDivider({
  variant = "ornate",
  className = "",
}: SectionDividerProps) {
  const src =
    variant === "ornate"
      ? "/images/generated/decorative/divider_byzantin.png"
      : "/images/generated/decorative/divider_simple.png";

  const height = variant === "ornate" ? 80 : 40;

  return (
    <div className={`mx-auto max-w-[600px] opacity-60 ${className}`}>
      <Image
        src={src}
        alt=""
        width={1920}
        height={height}
        className="h-auto w-full"
        aria-hidden="true"
      />
    </div>
  );
}
