import Image from "next/image";

interface OrnamentCornerProps {
  position: "top-left" | "top-right" | "bottom-left" | "bottom-right";
  size?: number;
  className?: string;
}

export default function OrnamentCorner({
  position,
  size = 96,
  className = "",
}: OrnamentCornerProps) {
  const positionClasses: Record<string, string> = {
    "top-left": "top-0 left-0",
    "top-right": "top-0 right-0 -scale-x-100",
    "bottom-left": "bottom-0 left-0 -scale-y-100",
    "bottom-right": "bottom-0 right-0 -scale-x-100 -scale-y-100",
  };

  return (
    <div
      className={`pointer-events-none absolute opacity-40 ${positionClasses[position]} ${className}`}
      aria-hidden="true"
    >
      <Image
        src="/images/generated/decorative/coin_ornement.png"
        alt=""
        width={size}
        height={size}
        className="h-auto w-auto"
        style={{ width: size, height: size }}
      />
    </div>
  );
}
